patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..13d16b73819f 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8292,6 +8292,57 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   if (L0 == R0 && match(L1, m_APInt(LC)) && match(R1, m_APInt(RC)))
     return isImpliedCondCommonOperandWithConstants(LPred, *LC, RPred, *RC);

+  // (icmp pred1 (add X, Y), X) and (icmp pred2 (add X, Y), Y) are
+  // equivalent for unsigned comparisons, because both check for overflow
+  // of the same addition.  Similarly for swapped operand order.
+  {
+    Value *X, *Y;
+    // Check all four operand pairings; the add must appear as an operand
+    // in both compares, and the other two operands must be the two addends.
+    auto MatchAddWithOperands =
+        [&](const Value *S0, const Value *O0, const Value *S1, const Value *O1) -> bool {
+      if (S0 != S1)
+        return false;
+      return match(S0, m_Add(m_Value(X), m_Value(Y))) &&
+             ((O0 == X && O1 == Y) || (O0 == Y && O1 == X));
+    };
+
+    bool LSumIsLHS, RSumIsLHS;
+    if (MatchAddWithOperands(L0, L1, R0, R1)) {
+      LSumIsLHS = true;
+      RSumIsLHS = true;
+    } else if (MatchAddWithOperands(L0, L1, R1, R0)) {
+      LSumIsLHS = true;
+      RSumIsLHS = false;
+    } else if (MatchAddWithOperands(L1, L0, R0, R1)) {
+      LSumIsLHS = false;
+      RSumIsLHS = true;
+    } else if (MatchAddWithOperands(L1, L0, R1, R0)) {
+      LSumIsLHS = false;
+      RSumIsLHS = false;
+    } else {
+      X = nullptr;
+    }
+
+    if (X) {
+      // Canonicalize both predicates to have the sum on the left.
+      auto GetCanonicalPred = [](CmpInst::Predicate Pred, bool SumIsLHS) {
+        if (!SumIsLHS)
+          Pred = ICmpInst::getSwappedPredicate(Pred);
+        return Pred;
+      };
+      CmpInst::Predicate LCanon = GetCanonicalPred(LHS->getPredicate(), LSumIsLHS);
+      CmpInst::Predicate RCanon = GetCanonicalPred(RPred, RSumIsLHS);
+      // Both must be unsigned and in the same equivalence class:
+      // ULT/ULE (overflow) or UGE/UGT (no overflow).  Since we canonicalized
+      // to have the sum on the left, we just need LCanon == RCanon and
+      // the predicate to be ULT or UGE.
+      if (LCanon == RCanon &&
+          (LCanon == CmpInst::ICMP_ULT || LCanon == CmpInst::ICMP_UGE))
+        return LHSIsTrue;
+    }
+  }
+
   if (LPred == RPred)
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);
